  1→//! HTTP CONNECT proxy server with domain filtering.
  2→//!
  3→//! Handles both `CONNECT host:port` (HTTPS) and plain HTTP forward requests.
  4→//! Connections from non-private IPs are rejected for security.
  5→
  6→use std::{
  7→    net::{IpAddr, Ipv4Addr, Ipv6Addr, SocketAddr},
  8→    sync::Arc,
  9→};
 10→
 11→use {
 12→    tokio::{
 13→        io::{AsyncBufReadExt, AsyncWriteExt, BufReader},
 14→        net::{TcpListener, TcpStream},
 15→    },
 16→    tracing::{debug, info, instrument, warn},
 17→};
 18→
 19→#[cfg(feature = "metrics")]
 20→use moltis_metrics::{counter, gauge, histogram};
 21→
 22→use crate::{
 23→    ApprovalSource, AuditSender, DomainDecision, FilterAction, FilterOutcome, NetworkAuditEntry,
 24→    NetworkProtocol, Result, domain_approval::DomainApprovalManager,
 25→};
 26→
 27→// Re-export for convenience; canonical definition is in `types.rs`.
 28→pub use crate::DEFAULT_PROXY_PORT;
 29→
 30→/// HTTP CONNECT proxy server that filters outbound connections by domain.
 31→///
 32→/// The proxy handles:
 33→/// - `CONNECT host:port` requests (used by HTTPS clients via `HTTPS_PROXY`)
 34→/// - Plain HTTP requests forwarded via `HTTP_PROXY`
 35→///
 36→/// For each connection, the domain is checked against the `DomainApprovalManager`.
 37→/// If the domain needs approval, the proxy holds the connection until a decision
 38→/// is made (or timeout).
 39→pub struct NetworkProxyServer {
 40→    listener_addr: SocketAddr,
 41→    filter: Arc<DomainApprovalManager>,
 42→    audit_tx: Option<AuditSender>,
 43→}
 44→
 45→impl NetworkProxyServer {
 46→    pub fn new(
 47→        listener_addr: SocketAddr,
 48→        filter: Arc<DomainApprovalManager>,
 49→        audit_tx: Option<AuditSender>,
 50→    ) -> Self {
 51→        Self {
 52→            listener_addr,
 53→            filter,
 54→            audit_tx,
 55→        }
 56→    }
 57→
 58→    /// Start the proxy server. This runs until the `shutdown` future completes.
 59→    pub async fn run(&self, shutdown: tokio::sync::watch::Receiver<bool>) -> Result<()> {
 60→        let listener = TcpListener::bind(self.listener_addr).await?;
 61→        info!(addr = %self.listener_addr, "network proxy listening");
 62→
 63→        loop {
 64→            tokio::select! {
 65→                accept = listener.accept() => {
 66→                    match accept {
 67→                        Ok((stream, peer)) => {
 68→                            if !is_private_or_loopback(&peer.ip()) {
 69→                                debug!(peer = %peer, "rejected proxy connection from non-private IP");
 70→                                drop(stream);
 71→                                continue;
 72→                            }
 73→                            let filter = Arc::clone(&self.filter);
 74→                            let audit_tx = self.audit_tx.clone();
 75→                            tokio::spawn(async move {
 76→                                if let Err(e) = handle_client(stream, peer, filter, audit_tx).await {
 77→                                    debug!(peer = %peer, error = %e, "proxy client error");
 78→                                }
 79→                            });
 80→                        },
 81→                        Err(e) => {
 82→                            warn!(error = %e, "proxy accept error");
 83→                        },
 84→                    }
 85→                },
 86→                _ = shutdown_signal(&shutdown) => {
 87→                    info!("network proxy shutting down");
 88→                    break;
 89→                },
 90→            }
 91→        }
 92→        Ok(())
 93→    }
 94→
 95→    /// The address the proxy is listening on.
 96→    pub fn addr(&self) -> SocketAddr {
 97→        self.listener_addr
 98→    }
 99→}
100→
101→/// Returns `true` if the IP is loopback or belongs to a private/link-local
102→/// range.  Used to reject connections from public IPs when the proxy binds
103→/// to `0.0.0.0` so container VMs on bridge/vmnet networks can reach it.
104→fn is_private_or_loopback(ip: &IpAddr) -> bool {
105→    match ip {
106→        IpAddr::V4(v4) => {
107→            v4.is_loopback()            // 127.0.0.0/8
108→                || v4.is_private()       // 10/8, 172.16/12, 192.168/16
109→                || v4.is_link_local()    // 169.254/16
110→                || is_cgnat(*v4) // 100.64/10 (Tailscale, CGNAT)
111→        },
112→        IpAddr::V6(v6) => {
113→            v6.is_loopback()             // ::1
114→                || is_ula(*v6) // fc00::/7
115→        },
116→    }
117→}
118→
119→/// CGNAT / shared address space (100.64.0.0/10), also used by Tailscale.
120→fn is_cgnat(ip: Ipv4Addr) -> bool {
121→    let octets = ip.octets();
122→    octets[0] == 100 && (octets[1] & 0xC0) == 64
123→}
124→
125→/// IPv6 Unique Local Address (fc00::/7).
126→fn is_ula(ip: Ipv6Addr) -> bool {
127→    (ip.segments()[0] & 0xFE00) == 0xFC00
128→}
129→
130→async fn shutdown_signal(rx: &tokio::sync::watch::Receiver<bool>) {
131→    let mut rx = rx.clone();
132→    while !*rx.borrow_and_update() {
133→        if rx.changed().await.is_err() {
134→            return;
135→        }
136→    }
137→}
138→
139→/// Handle a single client connection.
140→///
141→/// Reads the first line to determine if it's a CONNECT request or a plain HTTP request.
142→#[instrument(skip(stream, filter, audit_tx), fields(peer = %peer))]
143→async fn handle_client(
144→    stream: TcpStream,
145→    peer: SocketAddr,
146→    filter: Arc<DomainApprovalManager>,
147→    audit_tx: Option<AuditSender>,
148→) -> Result<()> {
149→    #[cfg(feature = "metrics")]
150→    {
151→        counter!("proxy_connections_total").increment(1);
152→        gauge!("proxy_connections_active").increment(1.0);
153→    }
154→
155→    let result = handle_client_inner(stream, peer, filter, audit_tx).await;
156→
157→    #[cfg(feature = "metrics")]
158→    gauge!("proxy_connections_active").decrement(1.0);
159→
160→    result
161→}
162→
163→async fn handle_client_inner(
164→    stream: TcpStream,
165→    peer: SocketAddr,
166→    filter: Arc<DomainApprovalManager>,
167→    audit_tx: Option<AuditSender>,
168→) -> Result<()> {
169→    let mut reader = BufReader::new(stream);
170→    let mut request_line = String::new();
171→    reader.read_line(&mut request_line).await?;
172→    let request_line = request_line.trim_end();
173→
174→    if request_line.is_empty() {
175→        return Err(crate::Error::message("empty request"));
176→    }
177→
178→    let parts: Vec<&str> = request_line.split_whitespace().collect();
179→    if parts.len() < 2 {
180→        return Err(crate::Error::message(format!(
181→            "malformed request line: {request_line}"
182→        )));
183→    }
184→
185→    let method = parts[0];
186→    let target = parts[1];
187→
188→    if method.eq_ignore_ascii_case("CONNECT") {
189→        handle_connect(reader, peer, target, filter, audit_tx).await
190→    } else {
191→        handle_http_forward(reader, peer, method, target, filter, audit_tx).await
192→    }
193→}
194→
195→/// Send an audit entry on a best-effort basis (non-blocking, drop if channel full).
196→fn emit_audit(tx: &Option<AuditSender>, entry: NetworkAuditEntry) {
197→    if let Some(ref sender) = *tx {
198→        let _ = sender.try_send(entry);
199→    }
200→}
201→
202→/// Handle an HTTP CONNECT tunnel request.
203→#[instrument(skip(reader, filter, audit_tx), fields(peer = %peer, target = %target))]
204→async fn handle_connect(
205→    mut reader: BufReader<TcpStream>,
206→    peer: SocketAddr,
207→    target: &str,
208→    filter: Arc<DomainApprovalManager>,
209→    audit_tx: Option<AuditSender>,
210→) -> Result<()> {
211→    let start = std::time::Instant::now();
212→
213→    // Parse host:port from CONNECT target.
214→    let (domain, port) = parse_host_port(target);
215→
216→    // Consume remaining request headers.
217→    loop {
218→        let mut line = String::new();
219→        reader.read_line(&mut line).await?;
220→        if line.trim().is_empty() {
221→            break;
222→        }
223→    }
224→
225→    // Use peer address as session identifier for now.
226→    let session = peer.to_string();
227→    let (action, approval_source) = filter.check_domain_with_source(&session, &domain).await;
228→
229→    match action {
230→        FilterAction::Allow => {
231→            #[cfg(feature = "metrics")]
232→            counter!("proxy_requests_total", "method" => "CONNECT", "result" => "allowed")
233→                .increment(1);
234→        },
235→        FilterAction::Deny => {
236→            #[cfg(feature = "metrics")]
237→            counter!("proxy_requests_total", "method" => "CONNECT", "result" => "denied")
238→                .increment(1);
239→            let resp = "HTTP/1.1 403 Forbidden\r\n\r\n";
240→            reader.get_mut().write_all(resp.as_bytes()).await?;
241→            emit_audit(&audit_tx, NetworkAuditEntry {
242→                timestamp: time::OffsetDateTime::now_utc(),
243→                session: session.clone(),
244→                domain: domain.clone(),
245→                port,
246→                protocol: NetworkProtocol::HttpConnect,
247→                action: FilterOutcome::Denied,
248→                method: None,
249→                url: None,
250→                status: None,
251→                bytes_sent: 0,
252→                bytes_received: 0,
253→                duration_ms: start.elapsed().as_millis() as u64,
254→                error: None,
255→                approval_source: None,
256→            });
257→            return Ok(());
258→        },
259→        FilterAction::NeedsApproval => {
260→            let (id, rx) = filter.create_request(&session, &domain).await;
261→            debug!(id = %id, domain = %domain, "waiting for domain approval");
262→            let decision = filter.wait_for_decision(rx).await;
263→            match decision {
264→                DomainDecision::Approved => {
265→                    #[cfg(feature = "metrics")]
266→                    counter!("proxy_requests_total", "method" => "CONNECT", "result" => "approved")
267→                        .increment(1);
268→                    // approval_source is overridden: user prompt approved it.
269→                },
270→                DomainDecision::Denied => {
271→                    #[cfg(feature = "metrics")]
272→                    counter!("proxy_requests_total", "method" => "CONNECT", "result" => "denied")
273→                        .increment(1);
274→                    let resp = "HTTP/1.1 403 Forbidden\r\n\r\n";
275→                    reader.get_mut().write_all(resp.as_bytes()).await?;
276→                    emit_audit(&audit_tx, NetworkAuditEntry {
277→                        timestamp: time::OffsetDateTime::now_utc(),
278→                        session: session.clone(),
279→                        domain: domain.clone(),
280→                        port,
281→                        protocol: NetworkProtocol::HttpConnect,
282→                        action: FilterOutcome::Denied,
283→                        method: None,
284→                        url: None,
285→                        status: None,
286→                        bytes_sent: 0,
287→                        bytes_received: 0,
288→                        duration_ms: start.elapsed().as_millis() as u64,
289→                        error: None,
290→                        approval_source: None,
291→                    });
292→                    return Ok(());
293→                },
294→                DomainDecision::Timeout => {
295→                    #[cfg(feature = "metrics")]
296→                    counter!("proxy_requests_total", "method" => "CONNECT", "result" => "denied")
297→                        .increment(1);
298→                    let resp = "HTTP/1.1 403 Forbidden\r\n\r\n";
299→                    reader.get_mut().write_all(resp.as_bytes()).await?;
300→                    emit_audit(&audit_tx, NetworkAuditEntry {
301→                        timestamp: time::OffsetDateTime::now_utc(),
302→                        session: session.clone(),
303→                        domain: domain.clone(),
304→                        port,
305→                        protocol: NetworkProtocol::HttpConnect,
306→                        action: FilterOutcome::Timeout,
307→                        method: None,
308→                        url: None,
309→                        status: None,
310→                        bytes_sent: 0,
311→                        bytes_received: 0,
312→                        duration_ms: start.elapsed().as_millis() as u64,
313→                        error: None,
314→                        approval_source: None,
315→                    });
316→                    return Ok(());
317→                },
318→            }
319→        },
320→    }
321→
322→    // Determine the effective approval source for allowed/approved connections.
323→    let effective_source = if action == FilterAction::NeedsApproval {
324→        Some(ApprovalSource::UserPrompt)
325→    } else {
326→        approval_source
327→    };
328→
329→    // Connect to upstream.
330→    let upstream_addr = format!("{domain}:{port}");
331→    let upstream = match TcpStream::connect(&upstream_addr).await {
332→        Ok(s) => s,
333→        Err(e) => {
334→            #[cfg(feature = "metrics")]
335→            counter!("proxy_upstream_errors_total", "error" => "connect_failed").increment(1);
336→            let resp = format!("HTTP/1.1 502 Bad Gateway\r\n\r\n{e}");
337→            reader.get_mut().write_all(resp.as_bytes()).await?;
338→            let action = if action == FilterAction::NeedsApproval {
339→                FilterOutcome::ApprovedByUser
340→            } else {
341→                FilterOutcome::Allowed
342→            };
343→            emit_audit(&audit_tx, NetworkAuditEntry {
344→                timestamp: time::OffsetDateTime::now_utc(),
345→                session: session.clone(),
346→                domain: domain.clone(),
347→                port,
348→                protocol: NetworkProtocol::HttpConnect,
349→                action,
350→                method: None,
351→                url: None,
352→                status: None,
353→                bytes_sent: 0,
354→                bytes_received: 0,
355→                duration_ms: start.elapsed().as_millis() as u64,
356→                error: Some(e.to_string()),
357→                approval_source: effective_source.clone(),
358→            });
359→            return Ok(());
360→        },
361→    };
362→
363→    // Send 200 Connection Established.
364→    let resp = "HTTP/1.1 200 Connection Established\r\n\r\n";
365→    reader.get_mut().write_all(resp.as_bytes()).await?;
366→
367→    // Bidirectional copy.
368→    let mut client_stream = reader.into_inner();
369→    let (mut client_read, mut client_write) = client_stream.split();
370→    let (mut upstream_read, mut upstream_write) = upstream.into_split();
371→
372→    let c2u = tokio::io::copy(&mut client_read, &mut upstream_write);
373→    let u2c = tokio::io::copy(&mut upstream_read, &mut client_write);
374→
375→    let (c2u_result, u2c_result) = tokio::join!(c2u, u2c);
376→
377→    let (bytes_sent, c2u_err) = match c2u_result {
378→        Ok(n) => (n, None),
379→        Err(e) => (0, Some(e.to_string())),
380→    };
381→    let (bytes_received, u2c_err) = match u2c_result {
382→        Ok(n) => (n, None),
383→        Err(e) => (0, Some(e.to_string())),
384→    };
385→    let error = c2u_err.or(u2c_err);
386→
387→    #[cfg(feature = "metrics")]
388→    {
389→        counter!("proxy_bytes_transferred_total", "direction" => "client_to_upstream")
390→            .increment(bytes_sent);
391→        counter!("proxy_bytes_transferred_total", "direction" => "upstream_to_client")
392→            .increment(bytes_received);
393→        histogram!("proxy_tunnel_duration_seconds").record(start.elapsed().as_secs_f64());
394→    }
395→
396→    let audit_action = if action == FilterAction::NeedsApproval {
397→        FilterOutcome::ApprovedByUser
398→    } else {
399→        FilterOutcome::Allowed
400→    };
401→    emit_audit(&audit_tx, NetworkAuditEntry {
402→        timestamp: time::OffsetDateTime::now_utc(),
403→        session,
404→        domain,
405→        port,
406→        protocol: NetworkProtocol::HttpConnect,
407→        action: audit_action,
408→        method: None,
409→        url: None,
410→        status: None,
411→        bytes_sent,
412→        bytes_received,
413→        duration_ms: start.elapsed().as_millis() as u64,
414→        error,
415→        approval_source: effective_source,
416→    });
417→
418→    Ok(())
419→}
420→
421→/// Handle a plain HTTP forward request (non-CONNECT).
422→///
423→/// Used when `HTTP_PROXY` is set and the client sends a full URL request.
424→#[instrument(skip(reader, filter, audit_tx), fields(peer = %peer, method = %method, target = %target))]
425→async fn handle_http_forward(
426→    mut reader: BufReader<TcpStream>,
427→    peer: SocketAddr,
428→    method: &str,
429→    target: &str,
430→    filter: Arc<DomainApprovalManager>,
431→    audit_tx: Option<AuditSender>,
432→) -> Result<()> {
433→    let start = std::time::Instant::now();
434→
435→    // Extract host from the URL.
436→    let domain = extract_host_from_url(target)?;
437→    let port = extract_port_from_url(target);
438→
439→    let session = peer.to_string();
440→    let (action, approval_source) = filter.check_domain_with_source(&session, &domain).await;
441→
442→    match action {
443→        FilterAction::Allow => {
444→            #[cfg(feature = "metrics")]
445→            counter!("proxy_requests_total", "method" => "HTTP", "result" => "allowed")
446→                .increment(1);
447→        },
448→        FilterAction::Deny => {
449→            #[cfg(feature = "metrics")]
450→            counter!("proxy_requests_total", "method" => "HTTP", "result" => "denied").increment(1);
451→            let resp = "HTTP/1.1 403 Forbidden\r\nContent-Length: 0\r\n\r\n";
452→            reader.get_mut().write_all(resp.as_bytes()).await?;
453→            emit_audit(&audit_tx, NetworkAuditEntry {
454→                timestamp: time::OffsetDateTime::now_utc(),
455→                session: session.clone(),
456→                domain: domain.clone(),
457→                port,
458→                protocol: NetworkProtocol::HttpForward,
459→                action: FilterOutcome::Denied,
460→                method: Some(method.to_string()),
461→                url: Some(target.to_string()),
462→                status: None,
463→                bytes_sent: 0,
464→                bytes_received: 0,
465→                duration_ms: start.elapsed().as_millis() as u64,
466→                error: None,
467→                approval_source: None,
468→            });
469→            return Ok(());
470→        },
471→        FilterAction::NeedsApproval => {
472→            let (id, rx) = filter.create_request(&session, &domain).await;
473→            debug!(id = %id, domain = %domain, "waiting for domain approval (HTTP)");
474→            let decision = filter.wait_for_decision(rx).await;
475→            match decision {
476→                DomainDecision::Approved => {
477→                    #[cfg(feature = "metrics")]
478→                    counter!("proxy_requests_total", "method" => "HTTP", "result" => "approved")
479→                        .increment(1);
480→                },
481→                DomainDecision::Denied => {
482→                    #[cfg(feature = "metrics")]
483→                    counter!("proxy_requests_total", "method" => "HTTP", "result" => "denied")
484→                        .increment(1);
485→                    let resp = "HTTP/1.1 403 Forbidden\r\nContent-Length: 0\r\n\r\n";
486→                    reader.get_mut().write_all(resp.as_bytes()).await?;
487→                    emit_audit(&audit_tx, NetworkAuditEntry {
488→                        timestamp: time::OffsetDateTime::now_utc(),
489→                        session: session.clone(),
490→                        domain: domain.clone(),
491→                        port,
492→                        protocol: NetworkProtocol::HttpForward,
493→                        action: FilterOutcome::Denied,
494→                        method: Some(method.to_string()),
495→                        url: Some(target.to_string()),
496→                        status: None,
497→                        bytes_sent: 0,
498→                        bytes_received: 0,
499→                        duration_ms: start.elapsed().as_millis() as u64,
500→                        error: None,
501→                        approval_source: None,
502→                    });
503→                    return Ok(());
504→                },
505→                DomainDecision::Timeout => {
506→                    #[cfg(feature = "metrics")]
507→                    counter!("proxy_requests_total", "method" => "HTTP", "result" => "denied")
508→                        .increment(1);
509→                    let resp = "HTTP/1.1 403 Forbidden\r\nContent-Length: 0\r\n\r\n";
510→                    reader.get_mut().write_all(resp.as_bytes()).await?;
511→                    emit_audit(&audit_tx, NetworkAuditEntry {
512→                        timestamp: time::OffsetDateTime::now_utc(),
513→                        session: session.clone(),
514→                        domain: domain.clone(),
515→                        port,
516→                        protocol: NetworkProtocol::HttpForward,
517→                        action: FilterOutcome::Timeout,
518→                        method: Some(method.to_string()),
519→                        url: Some(target.to_string()),
520→                        status: None,
521→                        bytes_sent: 0,
522→                        bytes_received: 0,
523→                        duration_ms: start.elapsed().as_millis() as u64,
524→                        error: None,
525→                        approval_source: None,
526→                    });
527→                    return Ok(());
528→                },
529→            }
530→        },
531→    }
532→
533→    // Determine the effective approval source for allowed/approved connections.
534→    let effective_source = if action == FilterAction::NeedsApproval {
535→        Some(ApprovalSource::UserPrompt)
536→    } else {
537→        approval_source
538→    };
539→
540→    // Read remaining headers.
541→    let mut headers = String::new();
542→    loop {
543→        let mut line = String::new();
544→        reader.read_line(&mut line).await?;
545→        if line.trim().is_empty() {
546→            break;
547→        }
548→        headers.push_str(&line);
549→    }
550→
551→    // Connect to upstream and forward the request.
552→    let upstream_addr = format!("{domain}:{port}");
553→    let mut upstream = match TcpStream::connect(&upstream_addr).await {
554→        Ok(s) => s,
555→        Err(e) => {
556→            #[cfg(feature = "metrics")]
557→            counter!("proxy_upstream_errors_total", "error" => "connect_failed").increment(1);
558→            let resp = format!("HTTP/1.1 502 Bad Gateway\r\n\r\n{e}");
559→            reader.get_mut().write_all(resp.as_bytes()).await?;
560→            let audit_action = if action == FilterAction::NeedsApproval {
561→                FilterOutcome::ApprovedByUser
562→            } else {
563→                FilterOutcome::Allowed
564→            };
565→            emit_audit(&audit_tx, NetworkAuditEntry {
566→                timestamp: time::OffsetDateTime::now_utc(),
567→                session: session.clone(),
568→                domain: domain.clone(),
569→                port,
570→                protocol: NetworkProtocol::HttpForward,
571→                action: audit_action,
572→                method: Some(method.to_string()),
573→                url: Some(target.to_string()),
574→                status: None,
575→                bytes_sent: 0,
576→                bytes_received: 0,
577→                duration_ms: start.elapsed().as_millis() as u64,
578→                error: Some(e.to_string()),
579→                approval_source: effective_source.clone(),
580→            });
581→            return Ok(());
582→        },
583→    };
584→
585→    // Convert absolute URL to relative path for upstream.
586→    let path = url_to_path(target);
587→    let request_line = format!("{method} {path} HTTP/1.1\r\n");
588→    upstream.write_all(request_line.as_bytes()).await?;
589→    upstream.write_all(headers.as_bytes()).await?;
590→    upstream.write_all(b"\r\n").await?;
591→
592→    // Bidirectional copy for the rest.
593→    let mut client_stream = reader.into_inner();
594→    let (mut client_read, mut client_write) = client_stream.split();
595→    let (mut upstream_read, mut upstream_write) = upstream.into_split();
596→
597→    let c2u = tokio::io::copy(&mut client_read, &mut upstream_write);
598→    let u2c = tokio::io::copy(&mut upstream_read, &mut client_write);
599→
600→    let (c2u_result, u2c_result) = tokio::join!(c2u, u2c);
601→
602→    let (bytes_sent, c2u_err) = match c2u_result {
603→        Ok(n) => (n, None),
604→        Err(e) => (0, Some(e.to_string())),
605→    };
606→    let (bytes_received, u2c_err) = match u2c_result {
607→        Ok(n) => (n, None),
608→        Err(e) => (0, Some(e.to_string())),
609→    };
610→    let error = c2u_err.or(u2c_err);
611→
612→    #[cfg(feature = "metrics")]
613→    {
614→        counter!("proxy_bytes_transferred_total", "direction" => "client_to_upstream")
615→            .increment(bytes_sent);
616→        counter!("proxy_bytes_transferred_total", "direction" => "upstream_to_client")
617→            .increment(bytes_received);
618→        histogram!("proxy_request_duration_seconds").record(start.elapsed().as_secs_f64());
619→    }
620→
621→    let audit_action = if action == FilterAction::NeedsApproval {
622→        FilterOutcome::ApprovedByUser
623→    } else {
624→        FilterOutcome::Allowed
625→    };
626→    emit_audit(&audit_tx, NetworkAuditEntry {
627→        timestamp: time::OffsetDateTime::now_utc(),
628→        session,
629→        domain,
630→        port,
631→        protocol: NetworkProtocol::HttpForward,
632→        action: audit_action,
633→        method: Some(method.to_string()),
634→        url: Some(target.to_string()),
635→        status: None,
636→        bytes_sent,
637→        bytes_received,
638→        duration_ms: start.elapsed().as_millis() as u64,
639→        error,
640→        approval_source: effective_source,
641→    });
642→
643→    Ok(())
644→}
645→
646→/// Parse `host:port` from a CONNECT target. Defaults port to 443 if not specified.
647→fn parse_host_port(target: &str) -> (String, u16) {
648→    if let Some((host, port_str)) = target.rsplit_once(':') {
649→        let port: u16 = port_str.parse().unwrap_or(443);
650→        (host.to_string(), port)
651→    } else {
652→        (target.to_string(), 443)
653→    }
654→}
655→
656→/// Extract the hostname from an absolute HTTP URL.
657→fn extract_host_from_url(url: &str) -> Result<String> {
658→    // Strip scheme.
659→    let after_scheme = url
660→        .strip_prefix("http://")
661→        .or_else(|| url.strip_prefix("https://"))
662→        .unwrap_or(url);
663→
664→    // Take up to the first '/' or end.
665→    let host_port = after_scheme.split('/').next().unwrap_or(after_scheme);
666→
667→    // Strip port if present.
668→    if let Some((host, _)) = host_port.rsplit_once(':') {
669→        Ok(host.to_string())
670→    } else {
671→        Ok(host_port.to_string())
672→    }
673→}
674→
675→/// Extract the port from an absolute HTTP URL. Defaults to 80 for http, 443 for https.
676→fn extract_port_from_url(url: &str) -> u16 {
677→    let is_https = url.starts_with("https://");
678→    let after_scheme = url
679→        .strip_prefix("http://")
680→        .or_else(|| url.strip_prefix("https://"))
681→        .unwrap_or(url);
682→
683→    let host_port = after_scheme.split('/').next().unwrap_or(after_scheme);
684→    if let Some((_, port_str)) = host_port.rsplit_once(':') {
685→        port_str.parse().unwrap_or(if is_https {
686→            443
687→        } else {
688→            80
689→        })
690→    } else if is_https {
691→        443
692→    } else {
693→        80
694→    }
695→}
696→
697→/// Convert an absolute URL to a relative path.
698→fn url_to_path(url: &str) -> String {
699→    let after_scheme = url
700→        .strip_prefix("http://")
701→        .or_else(|| url.strip_prefix("https://"))
702→        .unwrap_or(url);
703→
704→    if let Some(slash_pos) = after_scheme.find('/') {
705→        after_scheme[slash_pos..].to_string()
706→    } else {
707→        "/".to_string()
708→    }
709→}
