717→    fn test_parse_host_port() {
718→        let (host, port) = parse_host_port("github.com:443");
719→        assert_eq!(host, "github.com");
720→        assert_eq!(port, 443);
721→
722→        let (host, port) = parse_host_port("example.com");
723→        assert_eq!(host, "example.com");
724→        assert_eq!(port, 443);
725→
726→        let (host, port) = parse_host_port("api.example.com:8080");
727→        assert_eq!(host, "api.example.com");
