763→
764→    #[test]
765→    fn test_is_private_or_loopback() {
766→        // Loopback
767→        assert!(is_private_or_loopback(&IpAddr::V4(Ipv4Addr::LOCALHOST)));
768→        assert!(is_private_or_loopback(&IpAddr::V6(Ipv6Addr::LOCALHOST)));
769→
770→        // Private ranges (RFC 1918)
771→        assert!(is_private_or_loopback(&"10.0.0.1".parse().unwrap()));
772→        assert!(is_private_or_loopback(&"172.17.0.1".parse().unwrap())); // Docker bridge
773→        assert!(is_private_or_loopback(&"192.168.64.1".parse().unwrap())); // macOS vmnet
774→
775→        // CGNAT / Tailscale
776→        assert!(is_private_or_loopback(&"100.64.0.1".parse().unwrap()));
777→        assert!(is_private_or_loopback(&"100.127.255.254".parse().unwrap()));
778→
779→        // Link-local
780→        assert!(is_private_or_loopback(&"169.254.1.1".parse().unwrap()));
781→
782→        // IPv6 ULA
783→        assert!(is_private_or_loopback(&"fd00::1".parse().unwrap()));
784→
785→        // Public IPs must be rejected
786→        assert!(!is_private_or_loopback(&"8.8.8.8".parse().unwrap()));
787→        assert!(!is_private_or_loopback(&"1.1.1.1".parse().unwrap()));
788→        assert!(!is_private_or_loopback(&"2001:db8::1".parse().unwrap()));
789→    }
