 23→/// Start polling for a single bot account.
 24→///
 25→/// Spawns a background task that processes updates until the returned
 26→/// `CancellationToken` is cancelled.
 27→pub async fn start_polling(
 28→    account_id: String,
 29→    config: TelegramAccountConfig,
 30→    accounts: AccountStateMap,
 31→    message_log: Option<Arc<dyn MessageLog>>,
 32→    event_sink: Option<Arc<dyn ChannelEventSink>>,
 33→) -> crate::Result<CancellationToken> {
 34→    // Build bot with a client timeout longer than the long-polling timeout (30s)
 35→    // so the HTTP client doesn't abort the request before Telegram responds.
 36→    let client = teloxide::net::default_reqwest_settings()
 37→        .timeout(std::time::Duration::from_secs(45))
 38→        .build()
 39→        .map_err(|source| crate::Error::external("build telegram client", source))?;
 40→    let bot = Bot::with_client(config.token.expose_secret(), client);
 41→
 42→    // Verify credentials and get bot username.
 43→    let me = bot.get_me().await?;
 44→    let bot_username = me.username.clone();
 45→
 46→    // Delete any existing webhook so long polling works.
 47→    bot.delete_webhook().send().await?;
 48→
 49→    // Register slash commands for autocomplete in Telegram clients.
 50→    let commands = vec![
 51→        BotCommand::new("new", "Start a new session"),
 52→        BotCommand::new("sessions", "List and switch sessions"),
 53→        BotCommand::new("agent", "Switch session agent"),
 54→        BotCommand::new("model", "Switch provider/model"),
 55→        BotCommand::new("sandbox", "Toggle sandbox and choose image"),
 56→        BotCommand::new("sh", "Enable shell command mode"),
 57→        BotCommand::new("clear", "Clear session history"),
 58→        BotCommand::new("compact", "Compact session (summarize)"),
 59→        BotCommand::new("context", "Show session context info"),
 60→        BotCommand::new("help", "Show available commands"),
 61→    ];
 62→    if let Err(e) = bot.set_my_commands(commands).await {
 63→        warn!(account_id, "failed to register bot commands: {e}");
 64→    }
 65→
 66→    info!(
 67→        account_id,
 68→        username = ?bot_username,
 69→        "telegram bot connected (webhook cleared)"
 70→    );
 71→
 72→    let cancel = CancellationToken::new();
 73→
 74→    let outbound = Arc::new(TelegramOutbound {
 75→        accounts: Arc::clone(&accounts),
 76→    });
 77→
 78→    let otp_cooldown = config.otp_cooldown_secs;
 79→    let state = AccountState {
 80→        bot: bot.clone(),
 81→        bot_username,
 82→        account_id: account_id.clone(),
 83→        config,
 84→        outbound,
 85→        cancel: cancel.clone(),
 86→        message_log,
 87→        event_sink,
 88→        otp: std::sync::Mutex::new(crate::otp::OtpState::new(otp_cooldown)),
 89→    };
 90→
 91→    {
 92→        let mut map = accounts.write().unwrap_or_else(|e| e.into_inner());
 93→        map.insert(account_id.clone(), state);
 94→    }
 95→
 96→    let cancel_clone = cancel.clone();
 97→    let aid = account_id.clone();
 98→    let poll_accounts = Arc::clone(&accounts);
 99→    tokio::spawn(async move {
100→        info!(account_id = aid, "starting telegram manual polling loop");
101→        let mut offset: i32 = 0;
102→
103→        loop {
104→            if cancel_clone.is_cancelled() {
105→                info!(account_id = aid, "telegram polling stopped");
106→                break;
107→            }
108→
109→            let result = bot
110→                .get_updates()
111→                .offset(offset)
112→                .timeout(30)
113→                .allowed_updates(vec![
114→                    AllowedUpdate::Message,
115→                    AllowedUpdate::EditedMessage,
116→                    AllowedUpdate::CallbackQuery,
117→                ])
118→                .await;
119→
120→            match result {
121→                Ok(updates) => {
122→                    debug!(
123→                        account_id = aid,
124→                        count = updates.len(),
125→                        "got telegram updates"
126→                    );
127→                    for update in updates {
128→                        offset = update.id.as_offset();
129→                        match update.kind {
130→                            UpdateKind::Message(msg) => {
131→                                debug!(
132→                                    account_id = aid,
133→                                    chat_id = msg.chat.id.0,
134→                                    "received telegram message"
135→                                );
136→                                if let Err(e) =
137→                                    handlers::handle_message_direct(msg, &bot, &aid, &poll_accounts)
138→                                        .await
139→                                {
140→                                    error!(
141→                                        account_id = aid,
142→                                        error = %e,
143→                                        "error handling telegram message"
144→                                    );
145→                                }
146→                            },
147→                            UpdateKind::EditedMessage(msg) => {
148→                                debug!(
149→                                    account_id = aid,
150→                                    chat_id = msg.chat.id.0,
151→                                    "received telegram edited message"
152→                                );
153→                                if let Err(e) =
154→                                    handlers::handle_edited_location(msg, &aid, &poll_accounts)
155→                                        .await
156→                                {
157→                                    error!(
158→                                        account_id = aid,
159→                                        error = %e,
160→                                        "error handling telegram edited message"
161→                                    );
162→                                }
163→                            },
164→                            UpdateKind::CallbackQuery(query) => {
165→                                debug!(
166→                                    account_id = aid,
167→                                    callback_data = ?query.data,
168→                                    "received telegram callback query"
169→                                );
170→                                if let Err(e) = handlers::handle_callback_query(
171→                                    query,
172→                                    &bot,
173→                                    &aid,
174→                                    &poll_accounts,
175→                                )
176→                                .await
177→                                {
178→                                    error!(
179→                                        account_id = aid,
180→                                        error = %e,
181→                                        "error handling telegram callback query"
182→                                    );
183→                                }
184→                            },
185→                            other => {
186→                                debug!(account_id = aid, "ignoring non-message update: {other:?}");
187→                            },
188→                        }
189→                    }
190→                },
191→                Err(e) => {
192→                    // Detect conflict error: another bot instance is running with the same token.
193→                    let is_conflict =
194→                        matches!(&e, RequestError::Api(ApiError::TerminatedByOtherGetUpdates));
195→
196→                    if is_conflict {
197→                        warn!(
198→                            account_id = aid,
199→                            "telegram bot disabled: another instance is already running with this token"
200→                        );
201→
202→                        // Request the gateway to disable this channel.
203→                        let event_sink = {
204→                            let accounts = poll_accounts.read().unwrap_or_else(|e| e.into_inner());
205→                            accounts.get(&aid).and_then(|s| s.event_sink.clone())
206→                        };
207→                        if let Some(sink) = event_sink {
208→                            sink.request_disable_account(
209→                                "telegram",
210→                                &aid,
211→                                "Another bot instance is already running with this token",
212→                            )
213→                            .await;
214→                        }
215→
216→                        // Cancel this polling loop and exit.
217→                        cancel_clone.cancel();
218→                        break;
219→                    }
220→
221→                    warn!(account_id = aid, error = %e, "telegram getUpdates failed");
222→                    tokio::time::sleep(std::time::Duration::from_secs(5)).await;
223→                },
224→            }
225→        }
226→    });
227→
228→    Ok(cancel)
229→}
