 50→impl WebFetchTool {
 51→    /// Build from config; returns `None` if disabled.
 52→    pub fn from_config(config: &WebFetchConfig) -> Option<Self> {
 53→        if !config.enabled {
 54→            return None;
 55→        }
 56→        let ssrf_allowlist: Vec<ipnet::IpNet> = config
 57→            .ssrf_allowlist
 58→            .iter()
 59→            .filter_map(|s| match s.parse::<ipnet::IpNet>() {
 60→                Ok(net) => Some(net),
 61→                Err(e) => {
 62→                    tracing::warn!("ignoring invalid ssrf_allowlist entry \"{s}\": {e}");
 63→                    None
 64→                },
 65→            })
 66→            .collect();
 67→        Some(Self {
 68→            max_chars: config.max_chars,
 69→            timeout: Duration::from_secs(config.timeout_seconds),
 70→            cache_ttl: Duration::from_secs(config.cache_ttl_minutes * 60),
 71→            max_redirects: config.max_redirects,
 72→            readability: config.readability,
 73→            ssrf_allowlist,
 74→            cache: Mutex::new(HashMap::new()),
 75→            proxy_url: None,
 76→            #[cfg(feature = "firecrawl")]
 77→            firecrawl_api_key: None,
 78→            #[cfg(feature = "firecrawl")]
 79→            firecrawl_base_url: crate::firecrawl::DEFAULT_BASE_URL.into(),
 80→            #[cfg(feature = "firecrawl")]
 81→            firecrawl_only_main_content: true,
 82→            #[cfg(feature = "firecrawl")]
 83→            firecrawl_fallback: false,
 84→        })
 85→    }
