131→    fn cache_set(&self, key: String, value: serde_json::Value) {
132→        if self.cache_ttl.is_zero() {
133→            return;
134→        }
135→        if let Ok(mut cache) = self.cache.lock() {
136→            if cache.len() > 100 {
