 56→/// A model discovered from a provider API (e.g. `/v1/models`).
 57→///
 58→/// Replaces bare `(String, String)` tuples so that optional metadata
 59→/// such as `created_at` can travel alongside the id/display_name pair.
 60→#[derive(Debug, Clone)]
 61→pub struct DiscoveredModel {
 62→    pub id: String,
 63→    pub display_name: String,
 64→    /// Unix timestamp from the API (e.g. OpenAI `created` field).
 65→    /// Used to sort models newest-first. `None` for static catalog entries.
 66→    pub created_at: Option<i64>,
 67→    /// Flagged by the provider as a recommended/flagship model.
 68→    /// Used to surface the most relevant models in the UI.
 69→    pub recommended: bool,
 70→}
 71→
 72→impl DiscoveredModel {
 73→    pub fn new(id: impl Into<String>, display_name: impl Into<String>) -> Self {
 74→        Self {
 75→            id: id.into(),
 76→            display_name: display_name.into(),
 77→            created_at: None,
 78→            recommended: false,
 79→        }
 80→    }
 81→
 82→    pub fn with_created_at(mut self, created_at: Option<i64>) -> Self {
 83→        self.created_at = created_at;
 84→        self
 85→    }
 86→
 87→    pub fn with_recommended(mut self, recommended: bool) -> Self {
 88→        self.recommended = recommended;
 89→        self
 90→    }
 91→}
