 93→/// Convert a static model catalog into `DiscoveredModel` entries, marking
 94→/// the first `recommended_count` as recommended.
 95→pub fn catalog_to_discovered(
 96→    catalog: &[(&str, &str)],
 97→    recommended_count: usize,
 98→) -> Vec<DiscoveredModel> {
 99→    catalog
100→        .iter()
101→        .enumerate()
102→        .map(|(i, (id, name))| {
103→            DiscoveredModel::new(*id, *name).with_recommended(i < recommended_count)
104→        })
105→        .collect()
106→}
