118→/// Separator between a model ID and its reasoning effort suffix.
119→const REASONING_SUFFIX_SEP: char = '@';
120→
121→/// Reasoning effort suffixes appended to model IDs.
122→const REASONING_SUFFIXES: &[(&str, moltis_agents::model::ReasoningEffort)] = &[
123→    ("reasoning-low", moltis_agents::model::ReasoningEffort::Low),
124→    (
125→        "reasoning-medium",
126→        moltis_agents::model::ReasoningEffort::Medium,
127→    ),
128→    (
129→        "reasoning-high",
130→        moltis_agents::model::ReasoningEffort::High,
131→    ),
132→];
133→
134→/// Split a model ID into (base_id, optional reasoning effort).
135→///
136→/// Examples:
137→/// - `"anthropic::claude-opus-4-5@reasoning-high"` → `("anthropic::claude-opus-4-5", Some(High))`
138→/// - `"gpt-4o"` → `("gpt-4o", None)`
139→#[must_use]
140→pub fn split_reasoning_suffix(
141→    model_id: &str,
142→) -> (&str, Option<moltis_agents::model::ReasoningEffort>) {
143→    if let Some((base, suffix)) = model_id.rsplit_once(REASONING_SUFFIX_SEP) {
144→        for &(tag, effort) in REASONING_SUFFIXES {
145→            if suffix == tag {
146→                return (base, Some(effort));
147→            }
148→        }
149→    }
150→    (model_id, None)

