 67→    /// Apply `thinking` configuration to an Anthropic request body based on
 68→    /// the configured reasoning effort.
 69→    fn apply_thinking(&self, body: &mut serde_json::Value) {
 70→        use moltis_agents::model::ReasoningEffort;
 71→        let Some(effort) = self.reasoning_effort else {
 72→            return;
 73→        };
 74→        let budget_tokens: u64 = match effort {
 75→            ReasoningEffort::Low => 4096,
 76→            ReasoningEffort::Medium => 10240,
 77→            ReasoningEffort::High => 32768,
 78→        };
 79→        body["thinking"] = serde_json::json!({
 80→            "type": "enabled",
 81→            "budget_tokens": budget_tokens,
 82→        });
 83→        // Extended thinking requires higher max_tokens than budget_tokens.
 84→        if let Some(max_tokens) = body["max_tokens"].as_u64()
 85→            && max_tokens <= budget_tokens
 86→        {
 87→            body["max_tokens"] = serde_json::json!(budget_tokens + 4096);
 88→        }
 89→    }
