 91→    async fn probe_request(&self) -> anyhow::Result<()> {
 92→        let (system_value, anthropic_messages) =
 93→            to_anthropic_messages(&[ChatMessage::user("ping")], false);
 94→
 95→        let mut body = serde_json::json!({
 96→            "model": self.model,
 97→            // Probe for reachability, not full extended-thinking behavior.
 98→            "max_tokens": 1,
 99→            "messages": anthropic_messages,
100→        });

