 19→/// Manages the OAuth 2.0 authorization code flow with PKCE.
 20→pub struct OAuthFlow {
 21→    config: OAuthConfig,
 22→    client: reqwest::Client,
 23→}
 24→
 25→/// Result of starting the OAuth flow.
 26→pub struct AuthorizationRequest {
 27→    pub url: String,
 28→    pub pkce: PkceChallenge,
 29→    pub state: String,
 30→}
 31→
 32→impl OAuthFlow {
 33→    pub fn new(config: OAuthConfig) -> Self {
 34→        Self {
 35→            config,
 36→            client: reqwest::Client::new(),
 37→        }
 38→    }
 39→
 40→    /// Build the authorization URL and generate PKCE + state.
 41→    pub fn start(&self) -> Result<AuthorizationRequest> {
 42→        #[cfg(feature = "metrics")]
 43→        counter!(oauth_metrics::FLOW_STARTS_TOTAL).increment(1);
 44→
 45→        let pkce = generate_pkce();
 46→        let state = generate_state();
 47→
 48→        let mut url = Url::parse(&self.config.auth_url)
 49→            .map_err(|source| Error::external(format!("invalid auth_url: {source}"), source))?;
 50→        url.query_pairs_mut()
 51→            .append_pair("response_type", "code")
 52→            .append_pair("client_id", &self.config.client_id)
 53→            .append_pair("redirect_uri", &self.config.redirect_uri)
 54→            .append_pair("code_challenge", &pkce.challenge)
 55→            .append_pair("code_challenge_method", "S256")
 56→            .append_pair("state", &state);
 57→
 58→        if let Some(resource) = &self.config.resource {
 59→            url.query_pairs_mut().append_pair("resource", resource);
 60→        }
 61→
 62→        if !self.config.scopes.is_empty() {
 63→            url.query_pairs_mut()
 64→                .append_pair("scope", &self.config.scopes.join(" "));
 65→        }
 66→
 67→        for (key, value) in &self.config.extra_auth_params {
 68→            url.query_pairs_mut().append_pair(key, value);
 69→        }
 70→
 71→        // Always include originator
 72→        url.query_pairs_mut().append_pair("originator", "pi");
 73→
 74→        Ok(AuthorizationRequest {
 75→            url: url.to_string(),
 76→            pkce,
 77→            state,
 78→        })
 79→    }
 80→
 81→    /// Exchange an authorization code for tokens.
 82→    pub async fn exchange(&self, code: &str, verifier: &str) -> Result<OAuthTokens> {
 83→        #[cfg(feature = "metrics")]
 84→        counter!(oauth_metrics::CODE_EXCHANGE_TOTAL).increment(1);
 85→
 86→        let mut form = vec![
 87→            ("grant_type".to_string(), "authorization_code".to_string()),
 88→            ("code".to_string(), code.to_string()),
 89→            ("redirect_uri".to_string(), self.config.redirect_uri.clone()),
 90→            ("client_id".to_string(), self.config.client_id.clone()),
 91→            ("code_verifier".to_string(), verifier.to_string()),
 92→        ];
 93→        if let Some(resource) = &self.config.resource {
 94→            form.push(("resource".to_string(), resource.clone()));
 95→        }
 96→
 97→        let result = self
 98→            .client
 99→            .post(&self.config.token_url)
100→            .form(&form)

