base_url = "https://gmn.example.com/v1"
wire_api = "responses"
models = ["gpt-5.3-codex"]
"#;
        let config: MoltisConfig = toml::from_str(toml_str).unwrap();
        let entry = config.providers.get("custom-mn").unwrap();
        assert_eq!(entry.wire_api, WireApi::Responses);
    }

    #[test]
    fn provider_entry_wire_api_defaults_to_chat_completions() {
        let toml_str = r#"
[providers.openai]
enabled = true
"#;
        let config: MoltisConfig = toml::from_str(toml_str).unwrap();
        let entry = config.providers.get("openai").unwrap();
        assert_eq!(entry.wire_api, WireApi::ChatCompletions);
    }

    #[test]
    fn provider_entry_wire_api_skip_serializing_default() {
        let entry = ProviderEntry::default();
        let serialized = toml::to_string(&entry).unwrap();
        assert!(
            !serialized.contains("wire_api"),
            "default wire_api should be skipped in serialization"
        );
    }

    #[test]
    fn provider_entry_wire_api_serializes_responses() {
        let entry = ProviderEntry {
            wire_api: WireApi::Responses,
            ..Default::default()
        };
        let serialized = toml::to_string(&entry).unwrap();
        assert!(
            serialized.contains("wire_api = \"responses\""),
            "non-default wire_api should be serialized"
        );
    }
}

//! Configuration validation engine.
//!
//! Validates TOML configuration files against the known schema, detects
//! unknown/misspelled fields, and reports security warnings.

use std::{collections::HashMap, path::Path};

use crate::schema::MoltisConfig;

/// Severity level for a diagnostic.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum Severity {
    Error,
    Warning,
    Info,
}

impl std::fmt::Display for Severity {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::Error => write!(f, "error"),
            Self::Warning => write!(f, "warning"),
            Self::Info => write!(f, "info"),
        }
    }
}

/// A single validation diagnostic.
#[derive(Debug, Clone)]
pub struct Diagnostic {
    pub severity: Severity,
    /// Category: "syntax", "unknown-field", "deprecated-field", "unknown-provider", "type-error",
    /// "security", "file-ref"
    pub category: &'static str,
    /// Dotted path, e.g. "server.bnd"
    pub path: String,
    pub message: String,
}

/// Result of validating a configuration file.
#[derive(Debug, Clone)]
pub struct ValidationResult {
    pub diagnostics: Vec<Diagnostic>,
    pub config_path: Option<std::path::PathBuf>,
}

impl ValidationResult {
    /// Returns `true` if any diagnostic is an error.
    #[must_use]
    pub fn has_errors(&self) -> bool {
        self.diagnostics
            .iter()
            .any(|d| d.severity == Severity::Error)
    }

    /// Count diagnostics by severity.
    #[must_use]
    pub fn count(&self, severity: Severity) -> usize {
        self.diagnostics
            .iter()
            .filter(|d| d.severity == severity)
            .count()
    }
}

// ── Schema tree for unknown-field detection ─────────────────────────────────

/// Represents the expected shape of the configuration schema.
enum KnownKeys {
    /// A struct with fixed field names.
    Struct(HashMap<&'static str, KnownKeys>),
    /// A map with dynamic keys (providers, mcp.servers, etc.) whose values
    /// have a known shape.
    Map(Box<KnownKeys>),
    /// A map with dynamic keys plus explicit static keys.
    MapWithFields {
        value: Box<KnownKeys>,
        fields: HashMap<&'static str, KnownKeys>,
    },
    /// An array of typed items.
    Array(Box<KnownKeys>),
    /// Scalar value — stop recursion.
    Leaf,
}

