        async fn send_text(
            &self,
            account_id: &str,
            to: &str,
            text: &str,
            reply_to: Option<&str>,
        ) -> moltis_channels::Result<()> {
            self.delivered.lock().await.push(DeliveredMessage {
                account_id: account_id.to_string(),
                to: to.to_string(),
                text: text.to_string(),
                reply_to: reply_to.map(ToString::to_string),
            });
            Ok(())
        }

