                        }

                        // Cancel this polling loop and exit.
                        cancel_clone.cancel();
                        break;
                    }

                    warn!(account_id = aid, error = %e, "telegram getUpdates failed");
                    tokio::time::sleep(std::time::Duration::from_secs(5)).await;
