        assert!(
            deprecated
                .iter()
                .any(|d| d.path == "memory.embedding_dimensions" && d.message.contains("ignored")),
            "expected ignored warning for embedding_dimensions"
        );
        assert!(
            !result.has_errors(),
            "legacy embedding fields should remain usable: {:?}",
            result.diagnostics
        );
    }

